<template>
  <div v-if="!loading">
    <HeaderBarLyrics />
    <main>
      <h3 style="text-align: center; text-decoration: underline;">Search Results</h3>
      <section v-for="track in tracks" :key="track.id">
        <router-link :to="{ name: 'LyricsPage', query: { id: track.data.id } }">
          <div class="tracks">
            <img :src="track.data.albumOfTrack.coverArt.sources[1].url" :alt="track.data.name" ref="imgRef" />
            <span>{{ track.data.name }}</span>
            <span>{{ track.data.artists.items[0].profile.name }}</span>
            <span>{{ track.data.albumOfTrack.name }}</span>
          </div>
        </router-link>
      </section>
    </main>
    <FooterBar />
  </div>
  <div v-else class="loading">
    <i class="fa-solid fa-spinner fa-spin fa-2xl" style="color: #000000;"></i>
    </div>
</template>

<script>
import { defineComponent } from 'vue';
import axios from 'axios';
import HeaderBarLyrics from './HeaderBarLyrics.vue';
import FooterBar from './FooterBar.vue';

// const key = 'f4487bb2c6msh22c9f47af6a89afp1fff00jsn02d41c155170';
const key = '073319e51emshf395f17a0ef0467p1a45a0jsn775ff17f94b1';
export default defineComponent({
  name: 'SearchResult',
  components: {
    HeaderBarLyrics,
    FooterBar,
  },
  data() {
    return {
      tracks: [],
      loading: true
    };
  },
  created() {
    const itemId = this.$route.query.q;
    this.search(itemId);
  },
  methods: {
    async search(q) {
      const options = {
        method: 'GET',
        url: `https://spotify23.p.rapidapi.com/search/`,
        params: {
          q: q,
          type: 'tracks',
          limit: '15',
        },
        headers: {
          'X-RapidAPI-Key': key,
          'X-RapidAPI-Host': 'spotify23.p.rapidapi.com',
        },
      };
      try {
        const response = await axios.request(options);
        this.tracks = response.data.tracks.items;
      } catch (error) {
        console.error(error);
      }
      this.loading = false;
    },
  },
});

</script>


<style scoped>
div{
  font-family: poppins;
}
.loading {
  display: flex;
  justify-content: center;
  align-items: center;
  height: 100vh;
}
main{
  margin: 3.5rem 0 0 0;
  min-height: 80vh;
}
section{
  padding: 5px;
}
a{
  text-decoration: none;
  color: black;
  font-family: bold;
}
.searcharea{
  width: 100%;
  display: flex;
  justify-content: center;
  align-items: center;
  padding-top: 1rem;
  margin: auto;
}
.tracks{
    display: flex;
    flex-direction: row;
    justify-content: space-between;
    align-items: center;
    padding: 0 1rem;
    border: 0px solid black;
  }
  .tracks>span{
    width: 30%;

  }
  section:nth-child(odd){
    background-color: rgb(245, 245, 245);

  }
  section:nth-child(even):hover{
    background-color: rgb(245, 245, 245);
  }
  @media (max-width: 700px){
    .tracks>img{
      display: none;
    }
  }
