        </div>
      </div>
      <div class="main">
        <div class="tit" v-for="tit in trackinfo" :key="tit.id">
            <h4>{{ tit.artists[0].name }} - {{ tit.name }}</h4>
        </div>
        <div class="songlyrics" v-for="lyric in lyrics" :key="lyric.id">
            <span>{{ lyric.words }}</span>
        </div>
        <div class="preview" v-for="preview in trackinfo" :key="preview.id" align="center" style="margin-top: 20px;">
          <h6>Audio Preview</h6>
          <audio :src="preview.preview_url" type="mp3" controls :alt="preview.name"> </audio>
        </div>
        <div class="spotify" v-for="spot in trackinfo" :key="spot.id" align="center">
          <i class="fa-brands fa-spotify"></i>
          <a :href="spot.uri">Open In Spotify</a>
        </div>
        <div class="mydown" align="center" style="padding-top: 10px;">
          <button class="todown" @click="downloader">CLICK TO DOWNLOAD 10/day<i class="fa-solid fa-download"></i></button> <br>
          <div class="vvv" v-if="downloadlink" >
            <a :href="downloadlink" style="text-decoration: underline;" >Download Link </a>
          </div>
        </div>
        <div class="mydown" align="center" style="padding-top: 10px;">
          <button class="todown" @click="downloaderhundred">CLICK TO DOWNLOAD 100/month<i class="fa-solid fa-download"></i></button> <br>
          <div class="vvv" v-if="downloadlinktwo" >
            <a :href="downloadlinktwo" style="text-decoration: underline;" >Download Link</a>
          </div>
        </div>
      </div>
        <div class="about" v-for="basic in trackinfo" :key="basic.id" style="background-color: black; color: white;">
          <h2>About</h2>
          <div class="Basicinfo" v-for="basic in trackinfo" :key="basic.id" style="background-color: black; color: white; padding: 1rem;">
            <div class="right">
              <img :src="basic.album.images[1].url" :alt="basic.name">
              <div class="title">
                <h2>{{ basic.name }}</h2>
                <div class="myartists" style="display: flex; flex-direction: row;">
                  <template v-for="(artist, index) in basic.artists" :key="artist.id">
                    <h4>{{ artist.name }}<span v-if="index < basic.artists.length - 1">, </span></h4>
                  </template>
                </div>
                <h5>Track {{ basic.track_number }} of {{ basic.album.total_tracks }}</h5>
                <h5>{{ basic.album.name }}</h5>
                <h5>{{ basic.album.release_date }}</h5>
                <div class="popularity">
                  <span v-if="basic.popularity <= 20"><i class="fa-solid fa-star" style="color: #ffffff;"></i></span>
                  <span v-else-if="basic.popularity > 20 && basic.popularity <= 40"><i class="fa-solid fa-star" style="color: #ffffff;"></i><i class="fa-solid fa-star" style="color: #ffffff;"></i></span>
                  <span v-else-if="basic.popularity > 40 && basic.popularity <= 60"><i class="fa-solid fa-star" style="color: #ffffff;"></i><i class="fa-solid fa-star" style="color: #ffffff;"></i><i class="fa-solid fa-star" style="color: #ffffff;"></i></span>
                  <span v-else-if="basic.popularity > 60 && basic.popularity <= 80"><i class="fa-solid fa-star" style="color: #ffffff;"></i><i class="fa-solid fa-star" style="color: #ffffff;"></i><i class="fa-solid fa-star" style="color: #ffffff;"></i><i class="fa-solid fa-star" style="color: #ffffff;"></i></span>
                  <span v-else-if="basic.popularity > 80 && basic.popularity <= 100"><i class="fa-solid fa-star" style="color: #ffffff;"></i><i class="fa-solid fa-star" style="color: #ffffff;"></i><i class="fa-solid fa-star" style="color: #ffffff;"></i><i class="fa-solid fa-star" style="color: #ffffff;"></i><i class="fa-solid fa-star" style="color: #ffffff;"></i></span>
                </div>
              </div>
            </div>
          </div>
          <div class v-if="basic.album.album_type === 'album'">
            <h2>Album Info</h2>
            <div class="about albabout">
              <div class="Basicinfo albuminfos">
                <div class="right">
                  <img :src="basic.album.images[1].url" :alt="basic.name">
                  <div class="title">
                    <h2>{{ basic.album.name }}</h2>
                    <div class="myartists" v-for="artists in basic.album.artists" :key="artists.id">
                      <h4>{{artists.name}}</h4>
                    </div>
                    <h5>{{ basic.album.release_date }}</h5>
                    <!-- <h5>{{ basic.album.label }}</h5> -->
                    <div class="tracklist">
                      <h6>Tracks:</h6>
                      <div class="albuminfo" v-for="albtracks in myalbums" :key="albtracks.id" style="display: flex; flex-wrap: wrap; gap: 1rem;">
                          <template v-for="(tracklist) in albtracks.tracks.items" :key="tracklist.id">
                            <a :style="{ borderBottom: isIdMatch(tracklist.id) ? '2px solid white' : 'normal' }" @click="updateIdAndReload(tracklist.id)" class="albumstname">
                              {{ tracklist.name }}
                            </a>
                          </template>
                      </div>
                    </div>
                  </div>
                </div>
              </div>
            </div>
          </div>
          <span></span>
        <span></span>
        <span></span>
        </div>
    </section>
    <div v-else class="loading">
      <i class="fa-solid fa-spinner fa-spin fa-2xl" style="color: #000000;"></i>
    </div>
    <FooterBar />
  </template>
  

<script>

import { defineComponent} from 'vue';
import axios from 'axios';
import HeaderBarLyrics from './HeaderBarLyrics.vue';
import FooterBar from './FooterBar.vue';

// const key = 'f4487bb2c6msh22c9f47af6a89afp1fff00jsn02d41c155170'; //opeyemi

//const key = '073319e51emshf395f17a0ef0467p1a45a0jsn775ff17f94b1'; //okeseyi4
const key = '230c4f1224msh6e3c2515f3af347p114161jsn3bc39c14a7ff'; //okeseyi5
export default defineComponent({
  name: 'LyricsPage',
  components: {
    HeaderBarLyrics,
    FooterBar,
  },
  data() {
    return {
      trackinfo: [],
      lyrics: [],
      downloadlink:null,
      downloadlinktwo: null,
      loading: true,
      myalbums: []
    }
  },
  created() {
    const itemId = this.$route.query.id;
  this.search(itemId)
    .then(() => {
      const alid = this.trackinfo[0].album.id; // Assuming trackinfo is an array, and you want to get the album ID of the first track
      this.info(alid);
    })
  },
  methods: {
  updateIdAndReload(newId) {
    const currentQuery = { ...this.$route.query };

    // Update the id parameter
    currentQuery.id = newId;

    // Generate the new URL with the updated query
    const newURL = `${this.$router.resolve({ query: currentQuery }).href}`;

    // Reload the page with the new URL
    window.location.href = newURL;
  },
  isIdMatch(id) {
    return id === this.$route.query.id;
  },
    // Downloader
    async downloader() {
      const itemId = this.$route.query.id;
      const downloads = {
        method: 'GET',
        url: `https://spotify-downloader1.p.rapidapi.com/download/` + itemId,
        headers: {
          'X-RapidAPI-Key': '230c4f1224msh6e3c2515f3af347p114161jsn3bc39c14a7ff', //okeseyi5
          // 'X-RapidAPI-Key': 'f4487bb2c6msh22c9f47af6a89afp1fff00jsn02d41c155170', okeseyi4
          'X-RapidAPI-Host': 'spotify-downloader1.p.rapidapi.com',
        },
      };

      try {
        const response = await axios.request(downloads);
        this.downloadlink = response.data.link;
      } catch (error) {
        console.error(error);
      }
    },
    async downloaderhundred() {
      const itemId = this.$route.query.id;
      const downloads = {
        method: 'GET',
        url: `https://spotify-downloader3.p.rapidapi.com/spotify/download/`,
        params: {
          url: 'https://open.spotify.com/track/' + itemId
        },
        headers: {
          'X-RapidAPI-Key': '073319e51emshf395f17a0ef0467p1a45a0jsn775ff17f94b1',
          'X-RapidAPI-Host': 'spotify-downloader3.p.rapidapi.com'
        },
      };

      try {
        const response = await axios.request(downloads);
        this.downloadlinktwo = response.data.audio;
      } catch (error) {
        console.error(error);
      }
    },
    // Lyrics
    async search(id) {
      const options = {
          method: 'GET',
          url: `https://spotify23.p.rapidapi.com/track_lyrics/`,
          params: {
            id: id
          },
          headers: {
            'X-RapidAPI-Key': key,
            'X-RapidAPI-Host': 'spotify23.p.rapidapi.com'
          }
        };
        
      
      const trackinf = {
        method: 'GET',
        url: `https://spotify23.p.rapidapi.com/tracks/`,
        params: {
          id: id
        },
        headers: {
          'X-RapidAPI-Key': key,
          'X-RapidAPI-Host': 'spotify23.p.rapidapi.com'
        },
      };
      try {
        const response = await axios.request(options);
        const trackings = await axios.request(trackinf);
        this.lyrics = response.data.lyrics.lines;
        this.trackinfo = trackings.data.tracks;
      }
        catch (error) {
          console.error(error);
        }
      this.loading = false;
    },
    async info(alid){
      const albuminfos = {
          method: 'GET',
          url: `https://spotify23.p.rapidapi.com/albums/`,
          params: {
            id: alid
          },
          headers: {
            'X-RapidAPI-Key': key,
            'X-RapidAPI-Host': 'spotify23.p.rapidapi.com'
          }
        };
      try {
        const response = await axios.request(albuminfos);
        // const trackings = await axios.request(trackinf);
        this.myalbums = response.data.albums;
        // this.trackinfo = trackings.data.tracks;
        // this.albumtype = trackings.data.tracks.album.album_type;
      }
        catch (error) {
          console.error(error);
        }
    }
  },
});
</script>
  
